import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  // ⭐ Helper function to display stars
  const renderStars = (rating) => {
    const fullStars = Math.floor(rating); // full stars
    const halfStar = rating % 1 >= 0.5; // half star
    const emptyStars = 5 - fullStars - (halfStar ? 1 : 0);

    return (
      <>
        {"★".repeat(fullStars)}
        {halfStar && "☆"}
        {"☆".repeat(emptyStars)}
      </>
    );
  };

  return (
    <section style={{ padding: "40px" }}>
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        🔥 Popular Products
      </h2>

      {/* Popular Products Grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "center" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                padding: "15px",
                background: "#fff",
                height: "200px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3 className="product-name">{item.name}</h3>

            {/* ⭐ Rating */}
            <p style={{ fontSize: "14px", color: "#f39c12", margin: "4px 0" }}>
              {renderStars(item.rating)} ({item.rating})
            </p>

            <p style={{ fontSize: "14px", color: "#555" }}>{item.description}</p>
            <p className="product-price">${item.price}</p>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#9d5b2e",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>

      {/* Featured Picks Section */}
      <div style={{ marginTop: "60px" }}>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          ✨ Featured Picks
        </h2>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(3, 1fr)",
            gap: "25px",
            maxWidth: "1000px",
            margin: "0 auto",
          }}
        >
          {[
            {
              title: "Unparalleled Sound",
              desc: "Experience crystal-clear audio with premium headphones.",
              img: "/images/products/feature1.jpg",
            },
            {
              title: "Stay Connected",
              desc: "Compact and stylish earphones for every occasion.",
              img: "/images/products/feature3.jpg",
            },
            {
              title: "Power in Every Pixel",
              desc: "Shop the latest laptops for work, gaming, and more.",
              img: "/images/products/feature5.jpg",
            },
          ].map((card, index) => (
            <div
              key={index}
              style={{
                position: "relative",
                height: "370px",
                backgroundImage: `url(${card.img})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                display: "flex",
                alignItems: "flex-end",
                color: "#fff",
              }}
            >
              <div
                style={{
                  background: "rgba(0,0,0,0.6)",
                  padding: "15px",
                  width: "100%",
                }}
              >
                <h3 style={{ margin: "0 0 10px" }}>{card.title}</h3>
                <p style={{ fontSize: "14px", marginBottom: "10px" }}>
                  {card.desc}
                </p>
                <button
                  style={{
                    padding: "8px 15px",
                    border: "none",
                    background: "#9d5b2e",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  Buy Now ↗
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ✅ Subscribe Section */}
      <div
        style={{
          marginTop: "80px",
          padding: "50px 20px",
          background: "#f4f4f4",
          textAlign: "center",
        }}
      >
        <h2 style={{ marginBottom: "15px" }}>📩 Subscribe to Our Newsletter</h2>
        <p style={{ marginBottom: "20px", color: "#555" }}>
          Stay updated with the latest deals and new arrivals!
        </p>
        <form
          style={{
            display: "flex",
            justifyContent: "center",
            maxWidth: "500px",
            margin: "0 auto",
          }}
        >
          <input
            type="email"
            placeholder="Enter your email"
            required
            style={{
              padding: "12px",
              flex: 1,
              border: "1px solid #ccc",
              borderRadius: "6px 0 0 6px",
            }}
          />
          <button
            type="submit"
            style={{
              padding: "12px 20px",
              border: "none",
              background: "#9d5b2e",
              color: "#fff",
              borderRadius: "0 6px 6px 0",
              cursor: "pointer",
            }}
          >
            Subscribe
          </button>
        </form>
      </div>
    </section>
  );
};

export default PopularProducts;
